const nodemailer = require('nodemailer');

// Create a transporter object using SMTP transport
let transporter = nodemailer.createTransport({
    service: 'gmail',
    auth: {
        user: 'your_email@gmail.com', // Your email address
        pass: 'your_password' // Your email password or app-specific password if using 2-factor authentication
    }
});

// Define email options
let mailOptions = {
    from: 'your_email@gmail.com', // Sender address
    to: 'recipient_email@example.com', // List of recipients
    subject: 'Test Email', // Subject line
    text: 'Hello from Nodemailer!', // Plain text body
    html: '<b>Hello from Nodemailer!</b>' // HTML body
};

// Send email
transporter.sendMail(mailOptions, function(error, info){
    if (error) {
        console.error('Error occurred:', error);
    } else {
        console.log('Email sent:', info.response);
    }
});
